import{_ as l,o as i,c as e,e as a}from"./app-DHLwyd6l.js";const n={},t=a(`<h1 id="闭包" tabindex="-1"><a class="header-anchor" href="#闭包"><span>闭包</span></a></h1><ul><li>介绍：一个函数声明了一个函数，并且内层函数使用了外层函数的变量</li><li>作用 <ul><li>延长变量生命周期，被使用的变量没有手动清除的话不会被垃圾回收机制回收</li><li>私有化变量</li></ul></li><li>应用场景 <ul><li>防抖</li><li>节流</li><li>函数柯里化</li></ul></li></ul><h2 id="滥用闭包" tabindex="-1"><a class="header-anchor" href="#滥用闭包"><span>滥用闭包</span></a></h2><ul><li>在循环中创建闭包：导致保存过多变量，引起内存泄漏</li><li>在全局创建闭包：保存的变量会一直在内存，直到页面关闭</li><li>闭包保存过多的变量和函数：保存太多变量和函数，会导致闭包内存过大，影响程序性能</li><li>在闭包中保存敏感信息：可能导致信息泄漏，影响系统安全</li><li>在闭包中保存了不必要的东西：导致代码可读性和可维护性变差</li></ul><h2 id="怎么解决闭包带来的内存泄漏" tabindex="-1"><a class="header-anchor" href="#怎么解决闭包带来的内存泄漏"><span>怎么解决闭包带来的内存泄漏</span></a></h2><ul><li>及时释放不再使用的闭包：不再使用时，将闭包设置为null</li><li>避免在循环中使用闭包</li><li>避免在全局使用闭包</li><li>避免在闭包中保存过多的变量和函数</li></ul><h2 id="函数柯里化" tabindex="-1"><a class="header-anchor" href="#函数柯里化"><span>函数柯里化</span></a></h2><ul><li>介绍：是一种接受多个参数的函数转换为一系列只接受单个参数的函数的技术。在柯里化函数中，每个柯里化函数只接受一个参数，并返回一个新的柯里化函数，直到所有参数都被接受完毕才返回最终结果。</li><li>场景：在函数式编程应用广泛，可以帮助简化代码，提高代码可读性和可维护性。</li></ul><h1 id="作用域" tabindex="-1"><a class="header-anchor" href="#作用域"><span>作用域</span></a></h1><ul><li>介绍：js的作用域指的是变量和函数能够访问的范围，js采取静态作用域，意思就是代码编写时，就决定了其作用域，不是在运行时决定</li><li>分为两种： <ol><li>全局作用域：指代码在任何地方都能访问的变量和函数，在浏览器上，全局作用域时window对象</li><li>局部作用域：指的是在函数内部定义的变量和函数，在函数外部，无法访问到函数内部的变量和函数</li></ol></li></ul><h1 id="执行上下文" tabindex="-1"><a class="header-anchor" href="#执行上下文"><span>执行上下文</span></a></h1><ul><li>介绍：js中一个非常重要的概念，用于描述代码执行的环境。每当js执行一段代码时，都会创建一个执行上下文对象存放到执行上下文栈中，用于追踪代码的执行。执行上下文对象包含当前代码执行的环境信息，例如函数、变量、参数、this等</li><li>有哪些 <ol><li>全局执行上下文：在系统执行时创建的第一个执行上下文栈，代表了整个系统的执行环境，在浏览器上，全局执行上下文指的是window对象</li><li>函数执行上下文：函数在每次调用时创建的执行上下文对象，代表函数的执行环境，每个函数都有自己的函数执行上下文</li><li>eval函数执行上下文：js内置的一个函数，没怎么见过</li></ol></li><li>上下文对象包括什么： <ol><li>变量对象：包含当前执行环境中的变量和函数</li><li>作用域链：作用域链是当前执行上下文能够访问到的变量列表，用于解析变量和函数的引用</li><li>this值：指向当前代码的执行对象</li></ol></li></ul><h2 id="执行上下文栈" tabindex="-1"><a class="header-anchor" href="#执行上下文栈"><span>执行上下文栈</span></a></h2><ul><li>js通过执行上下文栈来管理执行上下文对象。执行上下文栈是一个先进后出的数据结构，每当js执行一段代码时，都会创建一个新的执行上下文压入栈顶，当代码执行完成后，js会将执行上下文对象从栈顶弹出并恢复上一个执行上下文对象</li><li>js在执行的时候，会不断的创建和销毁只想上下文对象并将他们压入和弹出指向上下文栈，直到程序结束或者遇到异常</li></ul><h2 id="作用域链" tabindex="-1"><a class="header-anchor" href="#作用域链"><span>作用域链</span></a></h2><ul><li>介绍：是js中实现变量和函数作用域的一种机制。当代码在当前作用域中无法找到变量或者函数时，会沿着作用域链向上查找，直到达到全局作用域为止，作用域链有一个或多个执行上下文对象组成，每个对象代表一个作用域</li></ul><h1 id="垃圾回收机制" tabindex="-1"><a class="header-anchor" href="#垃圾回收机制"><span>垃圾回收机制</span></a></h1><ul><li>介绍：js具有自动垃圾回收机制，也就是执行环境会管理代码执行过程中的内存</li><li>原理：垃圾收集器定期收集那些不存在使用的变量，然后释放其内存</li><li>方法 <ol><li>标记清除：垃圾回收机制执行时从全局对象出发扫描内存中的所有对象，能够到达的对象都是需要的，那些达到不了的对象就要被标记回收</li><li>引用计数：记录每个值的引用次数，如果被引用数就加1，多次引用会累加，失去引用数就减1，当引用数为0时，下次垃圾回收机制执行时就会回收这个值</li></ol></li></ul><h1 id="js数据类型" tabindex="-1"><a class="header-anchor" href="#js数据类型"><span>js数据类型</span></a></h1><ul><li>基本数据类型：number、string、Boolean、null、undefined、symbol、bigint</li><li>复杂数据类型：object、array、function</li></ul><h2 id="判断类型的方法" tabindex="-1"><a class="header-anchor" href="#判断类型的方法"><span>判断类型的方法</span></a></h2><ul><li>typeof操作符：可以判断一个变量是不是简单数据类型并返回一个字符串表示类型，但是判断null的时候也会返回object（历史遗留问题）</li></ul><div class="language-text line-numbers-mode" data-ext="text" data-title="text"><pre class="language-text"><code>此外，判断复杂数据类型时
typeof {}; // 返回 &quot;object&quot;
typeof []; // 返回 &quot;object&quot;
typeof function() {}; // 返回 &quot;function&quot;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>instanceof操作符：可以用来判断一个对象是否是一个构造函数的实例并返回一个布尔值，如果用来判断简单数据类型时会抛出类型错误</li></ul><div class="language-text line-numbers-mode" data-ext="text" data-title="text"><pre class="language-text"><code>const obj = {};
obj instanceof Object; // 返回 true
const arr = [];
arr instanceof Array; // 返回 true
function Person() {}
const p = new Person();
p instanceof Person; // 返回 true
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Object.prototype.toString()方法：可以获取一个变量的具体类型，并返回格式为[object 类型]的字符串</li></ul><div class="language-text line-numbers-mode" data-ext="text" data-title="text"><pre class="language-text"><code>Object.prototype.toString.call(123); // 返回 &quot;[object Number]&quot;
Object.prototype.toString.call(&#39;Hello&#39;); // 返回 &quot;[object String]&quot;
Object.prototype.toString.call(true); // 返回 &quot;[object Boolean]&quot;
Object.prototype.toString.call(undefined); // 返回 &quot;[object Undefined]&quot;
Object.prototype.toString.call(null); // 返回 &quot;[object Null]&quot;
Object.prototype.toString.call(Symbol(&#39;mySymbol&#39;)); // 返回 &quot;[object Symbol]&quot;
Object.prototype.toString.call(BigInt(12345678901234567890n)); // 返回 &quot;[object BigInt]&quot;
Object.prototype.toString.call({}); // 返回 &quot;[object Object]&quot;
Object.prototype.toString.call([]); // 返回 &quot;[object Array]&quot;
Object.prototype.toString.call(function() {}); // 返回 &quot;[object Function]&quot;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Array.isArray()方法：判断一个变量是否是数组类型，并返回一个布尔值</li></ul><h1 id="js原型" tabindex="-1"><a class="header-anchor" href="#js原型"><span>js原型</span></a></h1><ul><li>介绍：js中每个对象都有原型对象（prototype），它包含了一些属性和方法，可以用__proto__来访问则这个属性。当我们试图访问一个对象的属性时，它不仅会在该对象自身查找，也会在该对象的原型以及原型上的原型上查找，直到查找到这个属性或者查找到达原型链的尽头</li></ul><h2 id="原型链" tabindex="-1"><a class="header-anchor" href="#原型链"><span>原型链</span></a></h2><ul><li>介绍：js中每个对象都有一个原型对象，原型对象也会有自己的原型对象，这样就形成了一个原型链。当访问对象的一个属性或者方法时，会先在自身查找该属性或方法，如果没有找到则会沿着原型链查找，直到找到该属性或者达到原型链的终点。如果到达终点仍然没有找到该属性，就会返回undefined。</li></ul><h2 id="继承" tabindex="-1"><a class="header-anchor" href="#继承"><span>继承</span></a></h2><h1 id="数组常用方法" tabindex="-1"><a class="header-anchor" href="#数组常用方法"><span>数组常用方法</span></a></h1><ul><li>增 <ol><li>unshift 头部添加，改变数组</li><li>push 尾部添加，改变数组</li><li>splice 插入添加，改变数组</li><li>concat 数组拼接，返回新数组，不改变原数组</li></ol></li><li>删 <ol><li>shift 头部删除，改变数组</li><li>pop 尾部删除，改变数组</li><li>splice 插入删除，改变数组</li><li>slice 数组切片，不改变原数组</li></ol></li><li>改 <ol><li>splice 可以进行删除和修改，改变数组</li></ol></li><li>查 <ol><li>find 返回符合条件的第一个元素</li><li>indexof 返回符合条件的第一个元素的下标</li><li>includes 返回是否一个布尔值表示是否存该元素</li></ol></li></ul><h1 id="深浅拷贝" tabindex="-1"><a class="header-anchor" href="#深浅拷贝"><span>深浅拷贝</span></a></h1><ul><li>介绍：我们知道，js中有两种数据类型，分别是基本数据类型和引用数据类型。在存储方面，基本数据类型时保存在栈内存中的，引用数据类型是保存在堆内存中，引用数据类型，而引用类型的变量是一个指向堆内存中实际对象的引用，是存放在栈中的</li><li>浅拷贝： <ul><li>介绍：创建一份新的数据，这个数据保留着原始数据值的一份拷贝</li><li>拷贝结果：如果属性是基本类型，拷贝的就是基本类型的值；如果属性是引用类型，则是拷贝引用类型的引用，就是浅拷贝只拷贝一层，深层次的引用类型则是共享内存地址。当其中一个对象修改了一个引用类型属性的时候会影响到另一个对象</li><li>常见的浅拷贝： <ol><li>Object.assign()：将一个或者多个元对象的可枚举的自身属性复制到目标对象，然后返回修改后的目标对象</li><li>Array.slice()/Array.concat()</li><li>扩展运算符</li><li>loadsh库的.clone()</li></ol></li></ul></li><li>深拷贝 <ul><li>介绍：在堆中开辟一个新的空间存放新对象，属性相同但是地址完全不同，当一个对象的修改不会影响到另一个对象</li><li>常见的深拷贝： <ol><li>loadsh.deepclone()</li><li>JSON.parse(JSON.stringify()) =&gt; 缺点:不能拷贝函数和正则，json处理正则后变成空对象，处理函数后变成null</li><li>手写递归遍历原对象进行拷贝</li></ol></li></ul></li></ul><h1 id="事件循环机制" tabindex="-1"><a class="header-anchor" href="#事件循环机制"><span>事件循环机制</span></a></h1><ul><li>首先，js是一门单线程语言，意味着同一时间只能处理一个任务。</li><li>事件循环可以简单描述为： <ol><li>首先js引擎执行任务队列的同步任务，直到同步任务执行完毕</li><li>然后js引擎执行微任务队列里面的微任务，直到微任务队列为空</li><li>之后js引擎从宏任务队列里面拿出来一个宏任务开始执行，直到宏任务队列为空</li><li>其中执行宏任务时可能也会产生同步任务，微任务和宏任务，这时候需要重复之前的步骤</li></ol></li><li>常见异步任务 <ul><li>微任务 <ol><li>promise的回调</li><li>async/await返回的promise</li><li>process.nextTick（Node.js）</li></ol></li><li>宏任务 <ol><li>script标签</li><li>定时器</li><li>requestAnimationFrame</li></ol></li></ul></li></ul><h2 id="js为什么是单线程的" tabindex="-1"><a class="header-anchor" href="#js为什么是单线程的"><span>js为什么是单线程的</span></a></h2><ul><li>js是一种单线程语言，这就意味着在同一时间只能执行一个事件，不能同时处理多个事件。</li><li>这是为了在浏览器实现交互效果而设计的。在js中主要操作的是dom，响应事件等任务，这些操作大多是用户交互和页面渲染相关的，需要快速执行。那么如果js是多线程的话，就会出现多个线程同时操作dom或者修改同一个变量的情况，这样就可能导致不可预料的结果。</li><li>所以js被设计成单线程，所有任务都有一个线程来操作，任务依次执行，前一个任务执行完之后才会执行下一个任务，保证了任务的顺序和可靠性，避从而免了多线程的冲突。</li><li>此外，虽然js是单线程，但是可以通过一些异步操作去实现并发执行任务，例如promise、async/await，但这些技术仍然遵循js的单线程</li></ul><h1 id="防抖-节流" tabindex="-1"><a class="header-anchor" href="#防抖-节流"><span>防抖&amp;节流</span></a></h1><ul><li>介绍：本质都是优化事件高频触发的一种手段 <ul><li>防抖debounce：n秒后执行事件，如果在n秒内重复执行，则重新计时</li><li>节流throttle：n秒内只执行一次，如果n秒内重复执行，只触发一次</li></ul></li><li>用法：都利用了闭包，都可以通过定时器触发，都是为了减少事件高频</li><li>应用场景 <ul><li>防抖：在连续的事件，只需要触发一次的回调的场景 <ol><li>搜索框输入，不在改变时触发响应</li><li>手机号、邮箱的验证</li><li>按钮点击事件</li><li>窗口的改变</li></ol></li><li>节流：在单位时间内只执行一次的场景 <ol><li>滚动加载，滚轮触底事件</li><li>鼠标移动事件</li><li>自动完成事件</li></ol></li></ul></li><li>代码实现：······</li></ul><h1 id="this对象" tabindex="-1"><a class="header-anchor" href="#this对象"><span>this对象</span></a></h1><ul><li>介绍：在函数运行时自动产生的一个内部对象，只能在函数内部使用，总是指向调用它的对象，并且一旦确定就不会再改变</li><li>使用： <ul><li>在全局中：this指向全局对象，也就是window对象</li><li>在函数中: this指向调用它的对象</li><li>在构造函数和类中：this指向通过new关键字创建的新对象</li></ul></li><li>this指向的修改： <ul><li>apply():临时改变一次this指向并且立即调用 <ul><li>方法：function.apply(thisArg, [argsArray]):thisArg表示要替换函数中的this的值，argsArray是一个数组或者类数组表示要传递给函数的参数</li></ul></li><li>call():临时改变一次this指向并且立即调用 <ul><li>用法：function.call(thisArg, arg1, arg2, ...)：thisArg表示要替换函数中的this的值，rg1、arg2等是要作为参数传递给函数的值</li></ul></li><li>bind():返回一个永久改变this指向的函数，不会立即执行 <ul><li>用法：function.bind(thisArg, arg1, arg2, ...)：thisArg表示要替换函数中的this的值，arg1、arg2等是在新函数执行时要作为参数传递给函数的值</li></ul></li></ul></li></ul><h1 id="js事件和事件流" tabindex="-1"><a class="header-anchor" href="#js事件和事件流"><span>js事件和事件流</span></a></h1><ul><li>js事件：可以理解为在html文档或者在浏览器中发生的一种交互操作，使页面具有交互操作常见的交互有鼠标事件、加载事件等</li><li>js事件流：因为dom是一个树结构，如果父子节点都绑定了事件，当触发了一个节点的事件，那么事件的执行顺序就存在先后问题，这就涉及到了事件流 <ul><li>事件流分为三个阶段：事件捕获 =&gt; 事件捕获 =&gt; 事件冒泡</li><li>事件冒泡是一个从下往上的传播方式，有目标节点逐渐向上传播到最高层的父节点</li><li>事件捕获和冒泡相反，是从最高层的节点逐渐向下传播到目标节点</li></ul></li><li>事件绑定监听函数：addEventListener(eventType, handler, useCapture)/事件移除监听函数：removeEventListener(eventType, handler, useCapture) <ul><li>eventType指定事件类型(不要加on)</li><li>handler是事件处理函数</li><li>useCapture是一个boolean用于指定是否在捕获阶段进行处理，一般设置为false与IE浏览器保持一致</li></ul></li></ul><h2 id="事件模型" tabindex="-1"><a class="header-anchor" href="#事件模型"><span>事件模型</span></a></h2><ul><li>标准事件模型：事件捕获 =&gt; 事件触发 =&gt; 事件冒泡</li><li>ie事件模型：事件触发 =&gt; 事件冒泡</li></ul><h1 id="什么是事件委托" tabindex="-1"><a class="header-anchor" href="#什么是事件委托"><span>什么是事件委托</span></a></h1><ul><li>介绍：字面意思就是把一个元素的响应事件的函数委托到另一个元素</li><li>用法：把一个或一组元素的事件委托到它的外层的元素上，真正绑定事件的是外层元素，不再是目标元素，当事件响应到目标元素上时，会通过冒泡机制触发绑定在外层元素的事件，然后在外层触发事件</li><li>使用场景： <ul><li>动态添加元素</li><li>处理大量元素的事件</li><li>处理嵌套元素的事件</li><li>提高代码的可维护性</li></ul></li><li>优点 <ol><li>简化代码</li><li>提高性能</li><li>动态添加元素</li></ol></li></ul>`,51),s=[t];function r(o,d){return i(),e("div",null,s)}const c=l(n,[["render",r],["__file","默写.html.vue"]]),h=JSON.parse('{"path":"/tools/docs/interview/JavaScript/Temp/%E9%BB%98%E5%86%99.html","title":"闭包","lang":"zh-CN","frontmatter":{},"headers":[{"level":2,"title":"滥用闭包","slug":"滥用闭包","link":"#滥用闭包","children":[]},{"level":2,"title":"怎么解决闭包带来的内存泄漏","slug":"怎么解决闭包带来的内存泄漏","link":"#怎么解决闭包带来的内存泄漏","children":[]},{"level":2,"title":"函数柯里化","slug":"函数柯里化","link":"#函数柯里化","children":[]},{"level":2,"title":"执行上下文栈","slug":"执行上下文栈","link":"#执行上下文栈","children":[]},{"level":2,"title":"作用域链","slug":"作用域链","link":"#作用域链","children":[]},{"level":2,"title":"判断类型的方法","slug":"判断类型的方法","link":"#判断类型的方法","children":[]},{"level":2,"title":"原型链","slug":"原型链","link":"#原型链","children":[]},{"level":2,"title":"继承","slug":"继承","link":"#继承","children":[]},{"level":2,"title":"js为什么是单线程的","slug":"js为什么是单线程的","link":"#js为什么是单线程的","children":[]},{"level":2,"title":"事件模型","slug":"事件模型","link":"#事件模型","children":[]}],"git":{},"filePathRelative":"tools/docs/interview/JavaScript/Temp/默写.md"}');export{c as comp,h as data};
